import React, { useEffect, useState, useRef } from "react";
import {
  Trash2,
  Pencil,
  Plus,
  ChevronDown,
  Search,
} from "lucide-react";
import { motion, AnimatePresence } from "framer-motion";
import { linkHomeDesign as design } from "../../design/linkHomeDesign";

const API = "http://localhost:5000/api/links";

const statusOptions = [
  { label: "Active", value: true },
  { label: "Inactive", value: false },
];

const LinkHome = () => {
  const [links, setLinks] = useState([]);
  const [view, setView] = useState("home");
  const [search, setSearch] = useState("");
  const [statusDropdown, setStatusDropdown] = useState(false);

  const statusRef = useRef(null);

  const [name, setName] = useState("");
  const [isActive, setIsActive] = useState(true);
  const [position, setPosition] = useState("");

  /* ================= FETCH ================= */
  const fetchLinks = async () => {
    const res = await fetch(API);
    const data = await res.json();

    const parents = data
      .filter((l) => !l.parent)
      .sort((a, b) => (a.order || 0) - (b.order || 0));

    setLinks(parents);
  };

  useEffect(() => {
    fetchLinks();
  }, []);

  /* ================= CLOSE DROPDOWN ================= */
  useEffect(() => {
    const handler = (e) => {
      if (!statusRef.current?.contains(e.target)) {
        setStatusDropdown(false);
      }
    };
    document.addEventListener("mousedown", handler);
    return () =>
      document.removeEventListener("mousedown", handler);
  }, []);

  /* ================= FILTERED ================= */
  const filteredLinks = links.filter((l) =>
    l.name.toLowerCase().includes(search.toLowerCase())
  );

  /* ================= OPTION B POSITION LOGIC ================= */
  const handleSubmit = async (e) => {
    e.preventDefault();

    const total = links.length;
    let newPosition = parseInt(position);

    if (!newPosition || newPosition < 1) {
      newPosition = total + 1;
    }

    if (newPosition > total + 1) {
      newPosition = total + 1;
    }

    // Shift existing links if inserting in middle
    if (newPosition <= total) {
      for (const link of links) {
        if ((link.order || 0) >= newPosition) {
          await fetch(`${API}/${link._id}`, {
            method: "PUT",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({
              order: (link.order || 0) + 1,
            }),
          });
        }
      }
    }

    // Create new link
    await fetch(API, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        name,
        isActive,
        parent: null,
        order: newPosition,
      }),
    });

    setName("");
    setIsActive(true);
    setPosition("");
    setView("home");
    fetchLinks();
  };

  return (
    <div className={design.pageWrapper}>
      <div className={design.container}>
        {/* ================= HEADER ================= */}
        <div className={design.header}>
          <h1 className={design.title}>
            Parent Navigation Links
          </h1>
          <p className={design.subtitle}>
            Manage only main menu navigation.
          </p>

          <div className={design.pathWrapper}>
            {view === "home" && (
              <span className={design.pathActive}>
                linkhome
              </span>
            )}

            {view === "add" && (
              <>
                <span
                  onClick={() => setView("home")}
                  className={design.path}
                >
                  linkhome
                </span>
                <span className={design.pathDivider}>/</span>
                <span className={design.pathActive}>
                  add-link
                </span>
              </>
            )}
          </div>
        </div>

        <AnimatePresence mode="wait">
          {/* ================= HOME VIEW ================= */}
          {view === "home" && (
            <motion.div
              key="home"
              initial={{ opacity: 0, x: -30 }}
              animate={{ opacity: 1, x: 0 }}
              exit={{ opacity: 0, x: 30 }}
              transition={{ duration: 0.3 }}
              className="space-y-6"
            >
              {/* NAVBAR */}
              <div className={design.navbar}>
                <div className={design.searchWrapper}>
                  <Search size={16} />
                  <input
                    type="text"
                    placeholder="Search link..."
                    value={search}
                    onChange={(e) =>
                      setSearch(e.target.value)
                    }
                    className={design.searchInput}
                  />
                </div>

                <div className={design.rightControls}>
                  <button
                    onClick={() => setView("add")}
                    className={design.addButton}
                  >
                    <Plus size={16} />
                    Add Link
                  </button>
                </div>
              </div>

              {/* TABLE */}
              {filteredLinks.length > 0 ? (
                <div className={design.table}>
                  {filteredLinks.map((link, index) => (
                    <div
                      key={link._id}
                      className={design.row}
                    >
                      <div>{index + 1}</div>
                      <div>{link.name}</div>
                      <div>
                        {link.isActive
                          ? "Active"
                          : "Inactive"}
                      </div>
                      <div className="flex justify-end gap-4">
                        <Pencil size={16} />
                        <Trash2
                          size={16}
                          className="text-red-500"
                        />
                      </div>
                    </div>
                  ))}
                </div>
              ) : (
                <div className={design.emptyState}>
                  No parent links found.
                </div>
              )}
            </motion.div>
          )}

          {/* ================= ADD VIEW ================= */}
          {view === "add" && (
            <motion.form
              key="add"
              initial={{ opacity: 0, x: 30 }}
              animate={{ opacity: 1, x: 0 }}
              exit={{ opacity: 0, x: -30 }}
              transition={{ duration: 0.3 }}
              onSubmit={handleSubmit}
              className={design.form}
            >
              {/* LINK NAME */}
              <input
                type="text"
                placeholder="Link Name"
                value={name}
                onChange={(e) =>
                  setName(e.target.value)
                }
                className={design.input}
                required
              />

              {/* POSITION */}
              <input
                type="number"
                placeholder="Position (optional)"
                value={position}
                onChange={(e) =>
                  setPosition(e.target.value)
                }
                className={design.positionInput}
              />

              {/* STATUS DROPDOWN */}
              <div
                className={design.dropdownWrapper}
                ref={statusRef}
              >
                <button
                  type="button"
                  onClick={() =>
                    setStatusDropdown(!statusDropdown)
                  }
                  className={design.dropdownButton}
                >
                  {isActive ? "Active" : "Inactive"}
                  <ChevronDown size={16} />
                </button>

                <AnimatePresence>
                  {statusDropdown && (
                    <motion.div
                      initial={{ opacity: 0, y: -6 }}
                      animate={{ opacity: 1, y: 0 }}
                      exit={{ opacity: 0 }}
                      className={design.dropdownMenu}
                    >
                      {statusOptions.map((option) => (
                        <div
                          key={option.label}
                          onClick={() => {
                            setIsActive(option.value);
                            setStatusDropdown(false);
                          }}
                          className={`${design.dropdownItem} ${
                            isActive === option.value
                              ? design.dropdownActive
                              : ""
                          }`}
                        >
                          {option.label}
                        </div>
                      ))}
                    </motion.div>
                  )}
                </AnimatePresence>
              </div>

              {/* BUTTONS */}
              <div className={design.buttonGroup}>
                <button
                  type="submit"
                  className={design.submitButton}
                >
                  Create
                </button>

                <button
                  type="button"
                  onClick={() => setView("home")}
                  className={design.cancelButton}
                >
                  Cancel
                </button>
              </div>
            </motion.form>
          )}
        </AnimatePresence>
      </div>
    </div>
  );
};

export default LinkHome;
